const pendingResponse = $input.all()[0]?.json;
const failedResponse = $input.all()[1]?.json;

const pendingList = pendingResponse?.data || [];
const failedList = failedResponse?.data || [];

const now = new Date();
const STALE_THRESHOLD_MINUTES = 30;

// 30분 이상 적체된 PENDING 항목 필터링
const staleItems = pendingList.filter(item => {
  const createdAt = new Date(item.createdAt);
  const diffMinutes = (now - createdAt) / (1000 * 60);
  return diffMinutes >= STALE_THRESHOLD_MINUTES;
});

// 알림 조건 체크
const alerts = [];

if (staleItems.length > 0) {
  alerts.push({
    type: 'WARNING',
    metric: 'stale_pending_outbox',
    count: staleItems.length,
    message: `⚠️ ${staleItems.length}개의 Outbox가 ${STALE_THRESHOLD_MINUTES}분 이상 PENDING 상태입니다.`
  });
}

if (staleItems.length >= 50) {
  alerts[0].type = 'CRITICAL';
  alerts[0].message = `🚨 ${staleItems.length}개의 Outbox가 ${STALE_THRESHOLD_MINUTES}분 이상 적체되었습니다! SQS/EventBridge 장애 의심`;
}

if (failedList.length > 0) {
  alerts.push({
    type: failedList.length >= 10 ? 'CRITICAL' : 'WARNING',
    metric: 'failed_outbox',
    count: failedList.length,
    message: failedList.length >= 10 
      ? `🚨 ${failedList.length}개의 Outbox가 FAILED 상태입니다! 즉시 확인 필요`
      : `⚠️ ${failedList.length}개의 Outbox가 FAILED 상태입니다.`
  });
}

// 자동 재발행 대상 (최대 10개)
const autoRepublishTargets = [
  ...staleItems.slice(0, 5),
  ...failedList.slice(0, 5)
].map(item => ({
  crawlTaskId: item.crawlTaskId,
  status: item.status,
  createdAt: item.createdAt
}));

return {
  timestamp: now.toISOString(),
  summary: {
    totalPending: pendingList.length,
    stalePending: staleItems.length,
    totalFailed: failedList.length,
    staleThresholdMinutes: STALE_THRESHOLD_MINUTES
  },
  alerts,
  hasAlerts: alerts.length > 0,
  hasCritical: alerts.some(a => a.type === 'CRITICAL'),
  autoRepublishTargets,
  shouldAutoRepublish: autoRepublishTargets.length > 0 && alerts.some(a => a.type === 'CRITICAL')
};

const data = $input.first().json;
const alerts = data.alerts;
const summary = data.summary;

const hasCritical = data.hasCritical;
const emoji = hasCritical ? '🚨' : '⚠️';
const color = hasCritical ? '#ff0000' : '#ffcc00';
const alertText = alerts.map(a => a.message).join('\n');

const slackMessage = {
  text: `${emoji} CrawlingHub Outbox Alert`,
  attachments: [
    {
      color: color,
      blocks: [
        {
          type: 'header',
          text: {
            type: 'plain_text',
            text: `${emoji} CrawlingHub Outbox 적체 알림`,
            emoji: true
          }
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: alertText
          }
        },
        {
          type: 'divider'
        },
        {
          type: 'section',
          fields: [
            {
              type: 'mrkdwn',
              text: `*총 PENDING*\n${summary.totalPending}개`
            },
            {
              type: 'mrkdwn',
              text: `*적체 PENDING (>${summary.staleThresholdMinutes}분)*\n${summary.stalePending}개`
            },
            {
              type: 'mrkdwn',
              text: `*FAILED*\n${summary.totalFailed}개`
            },
            {
              type: 'mrkdwn',
              text: `*자동 재발행 대상*\n${data.autoRepublishTargets.length}개`
            }
          ]
        },
        {
          type: 'context',
          elements: [
            {
              type: 'mrkdwn',
              text: `⏰ ${data.timestamp}`
            }
          ]
        }
      ]
    }
  ]
};

return { 
  slackMessage, 
  shouldAutoRepublish: data.shouldAutoRepublish,
  autoRepublishTargets: data.autoRepublishTargets
};

